import scala.xml.{Elem, XML}
import scala.util.Try

class ConfigurationService {

  case class Setting(name: String, value: String)

  def parseConfiguration(xmlString: String): Try[List[Setting]] = {
    Try {
      val xml: Elem = XML.loadString(xmlString)

      val explicitSettings = (xml \\ "setting").map { node =>
        val name = node \@ "name"
        val value = node.text.trim
        Setting(name, value)
      }.toList

      val featureFlags = (xml \\ "feature").map { node =>
        val name = node \@ "name"
        val enabled = node \@ "enabled"
        Setting(s"feature.$name", enabled)
      }.toList

      val networkHost = (xml \\ "network" \ "host").text.trim
      val networkSetting = if (networkHost.nonEmpty) List(Setting("network.host", networkHost)) else Nil

      explicitSettings ++ featureFlags ++ networkSetting
    }
  }

  def getSettingValue(xmlString: String, settingName: String): Try[Option[String]] = {
    parseConfiguration(xmlString).map { settings =>
      settings.find(_.name == settingName).map(_.value)
    }
  }
}